#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int shortestJobFirst(vector<int>& burstTimes) {
        sort(burstTimes.begin(), burstTimes.end());
        long long total_waiting_time = 0;
        long long current_time = 0;
        for (int burst_time : burstTimes) {
            current_time += burst_time;
            total_waiting_time += current_time - burst_time;
        }
        return total_waiting_time;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N;
    cin >> N;
    vector<int> burstTimes(N);
    for (int i = 0; i < N; i++) cin >> burstTimes[i];
    Solution sol;
    cout << sol.shortestJobFirst(burstTimes) << "\n";
    return 0;
}
